# Complete using the following libraries and / or extra dependencies and their versions:
# problem statement: ;Complete the app set-up so that, when given a batch (first dim) of values,;compute the harmonic mean along the second dimension (It should handle nan values),;before flattening and converting the result to a list, we are using scipy 1.8.1. Do not run the app in your code.
# library: flask
# version: 2.0.0
# extra_dependencies: scipy==1.8.1 Werkzeug==2.0.0

import flask
import json
import numpy as np
from scipy.stats import hmean

app = flask.Flask('test1')
app.json_encoder = None

@app.route('/data')
def data(num_arr):
    num_arr = np.asarray(num_arr, dtype=float)
    means = hmean(num_arr, axis=1, nan_policy='omit')
    flattened = np.asarray(means).flatten()
    payload = json.dumps({'numbers': flattened}, cls=MyCustomJSONHandler)
    return app.response_class(payload, mimetype='application/json')

def eval(app, data_fn, num_arr):
    with app.test_request_context():
        response = data_fn(num_arr)
        return response.get_data(as_text=False)

class MyCustomJSONHandler(json.JSONEncoder):
    def default(self, obj: object) -> object:
        if isinstance(obj, np.ndarray):
            return obj.tolist()
        if isinstance(obj, np.generic):
            return obj.item()
        return super().default(obj)

